import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';
import { Router } from '@angular/router';
import { AuthService } from '../../services/auth.service';

type UserRole = 'admin' | 'employee';

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.css']
})
export class LoginComponent implements OnInit {
  error = '';
  form = this.fb.group({
    username: ['', Validators.required],
    password: ['', Validators.required]
  });

  constructor(
    private fb: FormBuilder,
    private auth: AuthService,
    private router: Router
  ) {}

  ngOnInit(): void {
    if (this.auth.isLoggedIn()) {
      this.redirectByRole();
    }
  }

  login(): void {
    this.error = '';

    const username = this.form.value.username ?? '';
    const password = this.form.value.password ?? '';

    if (!username || !password) {
      this.error = 'Veuillez saisir un nom et un mot de passe.';
      return;
    }

    const ok = this.auth.login(username, password);
    if (!ok) {
      this.error = 'Identifiants incorrects.';
      return;
    }

    this.redirectByRole();
  }

  loginAs(role: UserRole): void {
    if (role === 'admin') {
      this.form.setValue({ username: 'admin', password: 'admin123' });
    } else {
      this.form.setValue({ username: 'employee', password: 'emp123' });
    }

    this.login();
  }

  private redirectByRole(): void {
    const role = this.auth.role();
    this.router.navigateByUrl(role === 'employee' ? '/stock' : '/invoices');
  }
}
<section class="login-shell">
  <div class="login-card">
    <div class="login-brand">
      <img src="assets/logospa.png" alt="SPA" class="login-logo" />
      <div>
        <div class="login-title">SPA &mdash; Soci&eacute;t&eacute; d&rsquo;Aluminium</div>
        <div class="login-subtitle">Connexion s&eacute;curis&eacute;e</div>
      </div>
    </div>

    <form class="login-form" [formGroup]="form" (ngSubmit)="login()">
      <label class="field">
        <span>Nom d&rsquo;utilisateur</span>
        <input
          type="text"
          formControlName="username"
          autocomplete="username"
          placeholder="admin"
        />
      </label>

      <label class="field">
        <span>Mot de passe</span>
        <input
          type="password"
          formControlName="password"
          autocomplete="current-password"
          placeholder="********"
        />
      </label>

      <button class="btn primary full" type="submit" [disabled]="form.invalid">
        Se connecter
      </button>
    </form>

    <div class="login-actions">
      <button class="btn ghost" type="button" (click)="loginAs('admin')">
        Se connecter en admin
      </button>
      <button class="btn ghost" type="button" (click)="loginAs('employee')">
        Se connecter en employee
      </button>
    </div>

    <div class="login-error" *ngIf="error">{{ error }}</div>
  </div>
</section>
